const matcher: any = match({
  "'success'": () => "OK",
  "'pending'": () => "PENDING",
  default: "assert"
})

console.log("matcher.onFail is throwOnDefault?", matcher.onFail?.toString())
console.log("matcher.meta:", JSON.stringify(matcher.meta))
try {
  matcher("failure")
} catch (e) {
  console.log("Caught error:", e)
}

import { match } from "arktype"

try {
  const responseHandler = match({
    "{ status: 'success', data: object }": (val) => {
      return `OK: ${JSON.stringify(val.data)}`
    },
    "{ status: 'error', code: number, reason: string }": (val) => {
      return `ERR ${val.code} ${val.reason}`
    },
    "{ status: 'pending' }": () => {
      return "PENDING"
    },
    default: "assert"
  })

  console.log("Success test:", responseHandler({ status: "success", data: { foo: "bar" } }))
  console.log("Error test:", responseHandler({ status: "error", code: 404, reason: "Not Found" }))
  console.log("Pending test:", responseHandler({ status: "pending" }))

  // This should throw
  console.log("Invalid test:")
  responseHandler({ status: "invalid" })
} catch (e) {
  console.error("Caught expected error:", e)
}

import { match } from "arktype"

try {
  const responseHandler = match
    .case({ status: "'success'", data: "object" }, (val) => {
      return `OK: ${JSON.stringify(val.data)}`
    })
    .case({ status: "'error'", code: "number", reason: "string" }, (val) => {
      return `ERR ${val.code} ${val.reason}`
    })
    .case({ status: "'pending'" }, () => {
      return "PENDING"
    })
    .default("assert")

  console.log("Success test:", responseHandler({ status: "success", data: { foo: "bar" } }))
  console.log("Error test:", responseHandler({ status: "error", code: 404, reason: "Not Found" }))
  console.log("Pending test:", responseHandler({ status: "pending" }))

  // This should throw
  console.log("Invalid test:")
  responseHandler({ status: "invalid" })
} catch (e) {
  console.error("Caught expected error:", e)
}

