  const t = type("{ status: 'success', data: 'object' }")
  console.log("type parsed successfully:", t)
} catch (e) {
  console.error("error parsing:", e)
}

import { match } from "arktype"

try {
  const responseHandler = match.at("status", {
    "'success'": (val) => {
      console.log("val in success:", val)
      return `OK: ${JSON.stringify((val as any).data)}`
    },
    "'error'": (val) => {
      console.log("val in error:", val)
      return `ERR ${(val as any).code} ${(val as any).reason}`
    },
    "'pending'": (val) => {
      console.log("val in pending:", val)
      return "PENDING"
    },
    default: "assert"
  })

  console.log("Success test:", responseHandler({ status: "success", data: { foo: "bar" } }))
  console.log("Error test:", responseHandler({ status: "error", code: 404, reason: "Not Found" }))
  console.log("Pending test:", responseHandler({ status: "pending" }))

  // This should throw
  console.log("Invalid test:")
  responseHandler({ status: "invalid" })
} catch (e) {
  console.error("Caught expected error:", e)
