import { scope } from "arktype"

try {
  const myScope = scope({
    successPayload: { status: "'success'", data: "object" },
    errorPayload: { status: "'error'", code: "number", reason: "string" },
    pendingPayload: { status: "'pending'" }
  })

  const responseHandler = myScope.match({
    successPayload: (val) => {
      return `OK: ${JSON.stringify(val.data)}`
    },
    errorPayload: (val) => {
      return `ERR ${val.code} ${val.reason}`
    },
    pendingPayload: () => {
      return "PENDING"
    },
    default: "assert"
  })

  console.log("Success test:", responseHandler({ status: "success", data: { foo: "bar" } }))
  console.log("Error test:", responseHandler({ status: "error", code: 404, reason: "Not Found" }))
  console.log("Pending test:", responseHandler({ status: "pending" }))

  // This should throw
  console.log("Invalid test:")
  responseHandler({ status: "invalid" })
} catch (e) {
  console.error("Caught expected error:", e)
}

